import {
  useRef,
  useState,
  useEffect,
  lazy,
  Suspense,
  forwardRef,
} from 'react'

import { useTextField } from 'react-aria'
import { Field, Textarea as TuiTextarea } from '@tangible/ui'
import type { SizeStandard } from '@tangible/ui'
import { Description, Label } from '../../base'

const DynamicEditor = lazy(() => import('../../dynamic/editor/DynamicEditor'))

export interface FieldsTextareaProps {
  dynamic?: unknown
  value?: string
  onChange?: (value: string) => void
  name?: string
  label?: string
  labelVisuallyHidden?: boolean
  description?: string
  descriptionVisuallyHidden?: boolean
  placeholder?: string
  readOnly?: boolean
  isDisabled?: boolean
  isRequired?: boolean
  isInvalid?: boolean
  error?: boolean
  className?: string
  maxlength?: number
  minlength?: number
  rows?: number
  required?: boolean
  identifier?: string
  size?: SizeStandard
}

/**
 * Dynamic path sub-component — rendered only when the `dynamic` prop is set.
 * Isolated here so `useTextField` (react-aria) is only called in this path.
 */
const DynamicTextarea = (props: FieldsTextareaProps) => {
  const [value, setValue] = useState(props.value ?? '')
  const ref = useRef<HTMLTextAreaElement | null>(null)

  const {
    labelProps,
    inputProps,
    descriptionProps,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } = useTextField({ ...props, inputElementType: 'textarea' } as any, ref as any)

  useEffect(() => {
    if (props.onChange) props.onChange(value)
  }, [value])

  return (
    <div className="tf-text-area tf-text-area-dynamic">
      {props.label &&
        <Label labelProps={labelProps} parent={props}>
          {props.label}
        </Label>}
      <Suspense fallback={null}>
        <DynamicEditor
          value={value}
          onChange={setValue}
          dynamic={props.dynamic}
          name={props.name}
          placeholder={props.placeholder}
          readOnly={props.readOnly}
          singleLine={false}
          inputProps={inputProps}
        />
      </Suspense>
      {props.description && (
        <Description descriptionProps={descriptionProps} parent={props}>
          {props.description}
        </Description>
      )}
    </div>
  )
}

/**
 * Textarea with two routing paths:
 * 1. dynamic → ProseMirror-based DynamicEditor (multi-line)
 * 2. plain → TUI Textarea + Field compound
 */
const TextArea = forwardRef<HTMLTextAreaElement, FieldsTextareaProps>((props, ref) => {
  const hasDynamic = Boolean(props.dynamic)

  if (hasDynamic) {
    return <DynamicTextarea {...props} />
  }

  return (
    <div className='tf-text-area'>
      <Field
        className={props.className}
        required={Boolean(props.isRequired)}
        disabled={Boolean(props.isDisabled || props.readOnly)}
        error={Boolean(props.isInvalid || props.error)}
      >
        {props.label &&
          <Field.Label hidden={Boolean(props.labelVisuallyHidden)}>
            {props.label}
          </Field.Label>}
        <Field.Control>
          <TuiTextarea
            ref={ref}
            size={props.size}
            placeholder={props.placeholder}
            readOnly={props.readOnly}
            rows={props.rows}
            maxLength={props.maxlength}
            minLength={props.minlength}
            required={props.required}
            name={props.name}
            value={props.value ?? ''}
            onChange={event => {
              if (props.onChange) props.onChange(event.target.value)
            }}
            data-identifier={props.identifier ?? ''}
          />
        </Field.Control>
        {props.description && (
          <Field.HelperText className={props.descriptionVisuallyHidden ? 'tui-visually-hidden' : undefined}>
            {props.description}
          </Field.HelperText>
        )}
      </Field>
    </div>
  )
})

export default TextArea

import {
  useRef,
  useEffect,
  useState,
  lazy,
  Suspense,
  forwardRef
} from 'react'

import { useTextField } from 'react-aria'
import { Field, TextInput as TuiTextInput } from '@tangible/ui'
import type { SizeStandard, TextInputType } from '@tangible/ui'

import Description from '../../base/field/Description'
import Label from '../../base/field/Label'
import { useInputMask, matchesMask } from '../../../utils/use-input-mask'

const DynamicEditor = lazy(() => import('../../dynamic/editor/DynamicEditor'))

/**
 * Text field with three routing paths:
 * 1. dynamic → ProseMirror-based DynamicEditor (lazy-loaded)
 * 2. inputMask (no dynamic) → TUI TextInput + useInputMask hook
 * 3. plain → TUI TextInput with optional prefix/suffix
 *
 * @see https://react-spectrum.adobe.com/react-aria/useTextField.html
 */

export interface FieldsTextProps {
  dynamic?: unknown
  inputMask?: string
  prefix?: string
  suffix?: string
  value?: string
  onChange?: (value: string) => void
  name?: string
  placeholder?: string
  readOnly?: boolean
  isDisabled?: boolean
  isRequired?: boolean
  isInvalid?: boolean
  error?: boolean
  label?: string
  labelVisuallyHidden?: boolean
  description?: string
  descriptionVisuallyHidden?: boolean
  className?: string
  inputClassName?: string
  size?: SizeStandard
  type?: TextInputType
}

/**
 * Dynamic path sub-component — rendered only when the `dynamic` prop is set.
 * Isolated here so `useTextField` (react-aria) is only called in this path.
 */
const DynamicTextField = (props: FieldsTextProps) => {
  const [value, setValue] = useState(props.value ?? '')
  const ref = useRef<HTMLInputElement | null>(null)
  const mountedRef = useRef(false)

  const {
    labelProps,
    inputProps,
    descriptionProps,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } = useTextField(props as any, ref as any)

  useEffect(() => {
    if (!mountedRef.current) {
      mountedRef.current = true
      return
    }
    if (props.onChange) props.onChange(value)
  }, [value])

  return (
    <div className="tf-text tf-text-dynamic">
      {props.label &&
        <Label labelProps={labelProps} parent={props}>
          {props.label}
        </Label>}
      <Suspense fallback={null}>
        <DynamicEditor
          value={value}
          onChange={setValue}
          dynamic={props.dynamic}
          name={props.name}
          placeholder={props.placeholder}
          readOnly={props.readOnly}
          prefix={props.prefix}
          suffix={props.suffix}
          singleLine={true}
          inputProps={inputProps}
        />
      </Suspense>
      {props.description &&
        <Description descriptionProps={descriptionProps} parent={props}>
          {props.description}
        </Description>}
    </div>
  )
}

const TextField = forwardRef<HTMLInputElement, FieldsTextProps>((props, ref) => {
  const {
    dynamic,
    inputMask,
    prefix,
    suffix,
  } = props

  const hasDynamic = Boolean(dynamic)

  const [value, setValue] = useState(props.value ?? '')
  const inputMaskRef = useRef<HTMLInputElement | null>(null)
  const mountedRef = useRef(false)

  useInputMask(inputMaskRef, !hasDynamic ? inputMask : null)

  useEffect(() => {
    if (!mountedRef.current) {
      mountedRef.current = true
      return
    }
    if (props.onChange) props.onChange(value)
  }, [value])

  /**
   * Dynamic path — delegate to DynamicTextField which calls useTextField.
   * Note: ref is not forwarded to the ProseMirror editor.
   */
  if (hasDynamic) {
    return <DynamicTextField {...props} />
  }

  // Validate initial mask value
  const getInitialMaskValue = () => {
    if (!inputMask || !value) return value
    const stripped = stripAffixes(value, prefix, suffix)
    return matchesMask(stripped, inputMask) ? value : ''
  }

  /**
   * Native path — TUI TextInput (with optional input mask, prefix, suffix)
   */
  return (
    <div className="tf-text tf-text-tui">
      <Field
        className={props.className}
        required={Boolean(props.isRequired)}
        disabled={Boolean(props.isDisabled || props.readOnly)}
        error={Boolean(props.isInvalid || props.error)}
      >
        {props.label &&
          <Field.Label hidden={Boolean(props.labelVisuallyHidden)}>
            {props.label}
          </Field.Label>}
        <Field.Control>
          <TuiTextInput
            ref={node => {
              if (typeof ref === 'function') ref(node)
              else if (ref) ref.current = node
              // TUI TextInput forwards its ref directly to the <input> element —
              // no querySelector needed.
              if (inputMask && node) {
                inputMaskRef.current = node
              }
            }}
            inputClassName={`tui-input-reset ${props.inputClassName ?? ''}`.trim()}
            size={props.size}
            type={props.type ?? 'text'}
            placeholder={props.placeholder}
            readOnly={props.readOnly}
            value={inputMask ? getInitialMaskValue() : value}
            onChange={event => setValue(event.target.value)}
            name={props.name ?? ''}
            prefix={prefix}
            suffix={suffix}
          />
        </Field.Control>
        {props.description &&
          // Field.HelperText has no `hidden` prop — apply `tui-visually-hidden`
          // directly as a className to visually hide while keeping it accessible.
          <Field.HelperText className={props.descriptionVisuallyHidden ? 'tui-visually-hidden' : undefined}>
            {props.description}
          </Field.HelperText>}
      </Field>
    </div>
  )
})

/**
 * Strip prefix/suffix from a stored value for mask validation.
 */
function stripAffixes(value: string, prefix?: string, suffix?: string): string {
  let result = value
  if (prefix && result.startsWith(prefix)) {
    result = result.slice(prefix.length)
  }
  if (suffix && result.endsWith(suffix)) {
    result = result.slice(0, result.length - suffix.length)
  }
  return result
}

export default TextField

